iv = bytes.fromhex("92745d97795fa9a97925a7bc475ee46e")
ct = bytes.fromhex("f1b4fa40f14aedd1fd141217a942ff0b2d71f46098e551be9e3459d7045b508c")

operations = ['AND', 'NOR', 'NAND', 'XOR']
def compute(a, b, op):
    res = None
    if op == 'AND':
        res = a & b
    elif op == 'NOR':
        res = not (a | b)
    elif op == 'NAND':
        res = not (a & b)
    elif op == 'XOR':
        res = a ^ b

    return int(res)

def evaluate_gg(wires, gate, x, y):
    Wc = [None] * 2
    op = operations[(x + y) % 4]

    for a in [0, 1]:
        for b in [0, 1]:
            La, pa = wires[0][a]
            Lb, pb = wires[1][b]
            
            pc = compute(pa, pb, op)

            Lc = xor(H(La, Lb), gate[2*pa + pb])
            Wc[pc] = (Lc, pc)

    return Wc

def evaluate_gc(ws, gates):
    intermediate_wires = []
    wires = ws

    new_wires = None
    for x in range(4):
        new_wires = []
        for y in range(4):
            Wa = wires[y]
            Wb = wires[(y + 1) % 4]
            Wc = evaluate_gg([Wa, Wb], gates[x][y], x, y)

            intermediate_wires.append(Wc)
            new_wires.append(Wc)

        wires = [w for w in new_wires]

    return intermediate_wires

def generate_secret(wires, gates):
    intermediate_wires = evaluate_gc(wires, gates)
    secret = b""

    for w in intermediate_wires:
        label, p = w[1]
        secret += bytes([label[-1]])

    return secret

def main():
    secret = generate_secret(wires, gates)
    
    cipher = AES.new(secret, AES.MODE_CBC, iv)
    flag = unpad(cipher.decrypt(ct), AES.block_size)

    print("RHUL{" + flag.decode() + "}")

if __name__ == "__main__":
    main()